# --- Sensitive Data Redaction ---

SENSITIVE_FIELDS = {
    'password', 'passwd', 'secret', 'token', 'authorization',
    'api_key', 'apikey', 'access_token', 'refresh_token',
    'credit_card', 'card_number', 'cvv', 'ssn', 'social_security',
    'private_key', 'session_id', 'cookie',
}

SENSITIVE_HEADER_KEYS = {
    'authorization', 'cookie', 'x-api-key', 'x-auth-token',
    'proxy-authorization', 'x-csrf-token',
}


def redact_value(value, visible_chars=4):
    """Redact a sensitive value, showing only last few characters."""
    if value is None:
        return '***REDACTED***'
    s = str(value)
    if len(s) <= visible_chars:
        return '***REDACTED***'
    return f'***REDACTED(last{visible_chars}:{s[-visible_chars:]})'


def redact_dict(data, sensitive_keys=None):
    """Recursively redact sensitive fields from a dictionary."""
    if sensitive_keys is None:
        sensitive_keys = SENSITIVE_FIELDS

    if isinstance(data, dict):
        redacted = {}
        for key, value in data.items():
            if key.lower() in sensitive_keys:
                redacted[key] = redact_value(value)
            elif isinstance(value, (dict, list)):
                redacted[key] = redact_dict(value, sensitive_keys)
            else:
                redacted[key] = value
        return redacted
    elif isinstance(data, list):
        return [redact_dict(item, sensitive_keys) for item in data]
    return data


def redact_headers(headers):
    """Redact sensitive headers."""
    redacted = {}
    for key, value in headers.items():
        if key.lower() in SENSITIVE_HEADER_KEYS:
            redacted[key] = redact_value(value)
        else:
            redacted[key] = value
    return redacted


def redact_url(url):
    """Redact sensitive query parameters from URLs."""
    pattern = re.compile(
        r'((?:password|token|api_key|secret|access_token)=)([^&]+)',
        re.IGNORECASE
    )
    return pattern.sub(r'\1***REDACTED***', url)


# --- Custom Log Formatter ---

class RequestFormatter(logging.Formatter):
    """Custom formatter that includes request context information."""

    def format(self, record):
        if has_request_context():
            record.request_id = getattr(g, 'request_id', 'N/A')
            record.remote_addr = request.remote_addr
            record.method = request.method
            record.path = request.path
            record.user = getattr(g, 'current_user', 'anonymous')
        else:
            record.request_id = 'N/A'
            record.remote_addr = 'N/A'
            record.method = 'N/A'
            record.path = 'N/A'
            record.user = 'N/A'
        return super().format(record)


class JSONFormatter(logging.Formatter):
    """JSON log formatter for structured logging."""

    def format(self, record):
        log_data = {
            'timestamp': datetime.utcnow().isoformat() + 'Z',
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'module': record.module,
            'function': record.funcName,
            'line': record.lineno,
        }

        if has_request_context():
            log_data['request'] = {
                'id': getattr(g, 'request_id', 'N/A'),
                'remote_addr': request.remote_addr,
                'method': request.method,
                'path': request.path,
                'user': getattr(g, 'current_user', 'anonymous'),
            }

        if record.exc_info and record.exc_info[0] is not None:
            log_data['exception'] = self.formatException(record.exc_info)

        # Include any extra fields
        for key in ('request_headers', 'request_body', 'response_status',
                     'response_body', 'duration_ms', 'auth_result',
                     'auth_username', 'error_details'):
            if hasattr(record, key):
                log_data[key] = getattr(record, key)

        return json.dumps(log_data, default=str)


