def setup_logging(app):
    """Configure comprehensive logging for the Flask application."""

    log_level = app.config.get('LOG_LEVEL', 'DEBUG')
    log_dir = app.config.get('LOG_DIR', 'logs')
    os.makedirs(log_dir, exist_ok=True)

    # Clear default handlers
    app.logger.handlers.clear()

    # --- Console Handler (human-readable) ---
    console_handler = logging.StreamHandler()
    console_handler.setLevel(logging.DEBUG)
    console_format = RequestFormatter(
        fmt='%(asctime)s [%(levelname)s] [%(request_id)s] [%(user)s] '
            '%(remote_addr)s %(method)s %(path)s - %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    console_handler.setFormatter(console_format)

    # --- JSON File Handler (structured, for log aggregation) ---
    json_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'app.json.log'),
        maxBytes=10 * 1024 * 1024,  # 10 MB
        backupCount=10
    )
    json_handler.setLevel(logging.DEBUG)
    json_handler.setFormatter(JSONFormatter())

    # --- Error File Handler (errors only) ---
    error_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'error.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=10
    )
    error_handler.setLevel(logging.ERROR)
    error_format = RequestFormatter(
        fmt='%(asctime)s [%(levelname)s] [%(request_id)s] [%(user)s] '
            '%(remote_addr)s %(method)s %(path)s\n%(message)s\n',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    error_handler.setFormatter(error_format)

    # --- Audit File Handler (authentication events) ---
    audit_logger = logging.getLogger('audit')
    audit_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'audit.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=20
    )
    audit_handler.setLevel(logging.INFO)
    audit_handler.setFormatter(JSONFormatter())
    audit_logger.addHandler(audit_handler)
    audit_logger.setLevel(logging.INFO)

    # --- Security Logger (for security events) ---
    security_logger = logging.getLogger('security')
    security_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'security.log'),
        maxBytes=10 * 1024 * 1024,
        backupCount=20
    )
    security_handler.setLevel(logging.WARNING)
    security_handler.setFormatter(JSONFormatter())
    security_logger.addHandler(security_handler)
    security_logger.setLevel(logging.WARNING)

    # Add handlers to app logger
    app.logger.addHandler(console_handler)
    app.logger.addHandler(json_handler)
    app.logger.addHandler(error_handler)
    app.logger.setLevel(getattr(logging, log_level))

    # Also configure werkzeug logger
    werkzeug_logger = logging.getLogger('werkzeug')
    werkzeug_logger.addHandler(console_handler)
    werkzeug_logger.addHandler(json_handler)

    app.logger.info("Logging configured successfully",
                     extra={'log_level': log_level, 'log_dir': log_dir})


